mapper.insert:
insert into email_verification_code (
    email, scene, code_hash, expire_time, used, send_ip
) values (
    #{email}, #{scene}, #{codeHash}, #{expireTime}, #{used}, #{sendIp}
)

mapper.select:
select create_time
from email_verification_code
where email = #{email}
  and scene = #{scene}
order by id desc
limit 1

select id, email, scene, code_hash, expire_time, used, send_ip, create_time, used_time
from email_verification_code
where email = #{email}
  and scene = #{scene}
  and used = 0
  and expire_time > #{now}
order by id desc
limit 1
